external_knowledge:
- 'overall fatalities' refers to the total deaths during the period;
- 'extra deaths beyond what was expected' refers to excess deaths;
- 'quite high' means total deaths greater than 5000;
- 'relatively low' means excess deaths less than 500.

sql:
SELECT start_date, total_deaths, excess_deaths
FROM mortality_data
WHERE start_date > '2020-01-01' AND total_deaths > 5000 AND excess_deaths < 500;

